mapper.select:
SELECT c1.course_id,c2.name as courseName,c1.student_id,s.name ,
       s.clazz, c1.credit,s.sex,c2.course_statue as courseStatus
FROM credit c1
LEFT JOIN student s ON c1.student_id = s.student_id
LEFT JOIN course c2 ON c1.course_id = c2.id

     AND c1.course_id = #{courseId}
     AND c1.student_id = #{studentId}
     AND c2.course_statue = #{courseStatus}
    AND c2.teacher_id = #{teacherId}

ORDER BY c1.course_id DESC

select c1.course_id, c1.credit,c2.name as course_name, c2.course_statue, c2.description, c2.term_period, t.name as teacher_name from credit c1 join course c2 on c1.course_id=c2.id join teacher t on c2.teacher_id=t.teacher_id
and c1.course_id = #{courseId}
and c2.name like concat('%', #{courseName}, '%')
and c2.course_statue = #{courseStatus}
and c1.student_id = #{studentId}
order by c1.course_id desc

select count(*) from credit c2
left join course c on c2.course_id=c.id
where c.teacher_id=#{teacherId}
